import{_ as l,o as i,c as e,O as t}from"./chunks/framework.c4f51971.js";const p=JSON.parse('{"title":"Logo 设计","description":"","frontmatter":{},"headers":[],"relativePath":"logo-design/index.md","filePath":"logo-design/index.md","lastUpdated":1775618461000}'),o={name:"logo-design/index.md"};function r(h,a,d,n,u,s){return i(),e("div",null,a[0]||(a[0]=[t('<h1 id="logo-设计" tabindex="-1">Logo 设计 <a class="header-anchor" href="#logo-设计" aria-label="Permalink to &quot;Logo 设计&quot;">​</a></h1><p>这份页面用于沉淀“智流”平台的 Logo 方向，不是最终定稿，而是后续视觉探索、草图输出、图形提炼和品牌统一的设计简报。</p><h2 id="核心理念" tabindex="-1">核心理念 <a class="header-anchor" href="#核心理念" aria-label="Permalink to &quot;核心理念&quot;">​</a></h2><p>“智流”平台的 Logo 需要同时表达四件事：</p><ul><li>智能调度</li><li>经验资产化</li><li>安全可控</li><li>自动化流转</li></ul><p>它不应该只是一个普通的科技图标，而应该是一个兼具智能感、流动感、控制感和执行感的现代符号。</p><h2 id="总体视觉定义" tabindex="-1">总体视觉定义 <a class="header-anchor" href="#总体视觉定义" aria-label="Permalink to &quot;总体视觉定义&quot;">​</a></h2><p>一句话总结：</p><p><strong>它是一个“智慧大脑”与“数据川流”在可控轨道内精准交汇的现代符号。</strong></p><p>整体视觉应该具备这些特征：</p><ul><li>抽象，而不是具象物品</li><li>动态，有数据和能量的流向</li><li>稳定，有边界感和掌控感</li><li>精准，能体现“调度”与“执行”的瞬间</li></ul><h2 id="基础构成元素" tabindex="-1">基础构成元素 <a class="header-anchor" href="#基础构成元素" aria-label="Permalink to &quot;基础构成元素&quot;">​</a></h2><h3 id="_1-主体图形" tabindex="-1">1. 主体图形 <a class="header-anchor" href="#_1-主体图形" aria-label="Permalink to &quot;1. 主体图形&quot;">​</a></h3><p>将中文“智”字右半部分的“日”做抽象变形，并与“大脑神经回路”或“数据流”图案融合。</p><p>目标不是做一个可识别的字体 Logo，而是提炼出一种同时带有：</p><ul><li>智慧感</li><li>数据流动感</li><li>川流方向感</li></ul><p>的核心识别图形。</p><h3 id="_2-环绕结构" tabindex="-1">2. 环绕结构 <a class="header-anchor" href="#_2-环绕结构" aria-label="Permalink to &quot;2. 环绕结构&quot;">​</a></h3><p>在主体图形外，引入圆环或无限符号 <code>∞</code> 的变体结构。</p><p>它代表：</p><ul><li>循环</li><li>网络</li><li>生态</li><li>可控边界</li></ul><p>这个结构可以是包裹式，也可以是穿透式，但必须强化“系统内调度”和“安全轨道”这层含义。</p><h3 id="_3-点睛符号" tabindex="-1">3. 点睛符号 <a class="header-anchor" href="#_3-点睛符号" aria-label="Permalink to &quot;3. 点睛符号&quot;">​</a></h3><p>在核心区域加入一个极简的闪电或箭头符号。</p><p>这个符号用于表达：</p><ul><li>智能决策</li><li>调度触发</li><li>精准执行</li></ul><p>它应该足够克制，避免喧宾夺主，但要让 Logo 在静态状态下也能有“下一秒就会执行”的张力。</p><h2 id="整体气质" tabindex="-1">整体气质 <a class="header-anchor" href="#整体气质" aria-label="Permalink to &quot;整体气质&quot;">​</a></h2><p>Logo 需要稳定落在下面四个关键词上：</p><ul><li>智能：有大脑和判断能力的感觉</li><li>流动：有数据、能量、路径和方向</li><li>控制：有聚合、稳定、可控的边界</li><li>精准：有高效触发和明确裁决的信号</li></ul><h2 id="色彩建议" tabindex="-1">色彩建议 <a class="header-anchor" href="#色彩建议" aria-label="Permalink to &quot;色彩建议&quot;">​</a></h2><p>推荐主色体系：</p><ul><li>主色：科技蓝 + 智慧紫渐变</li><li>高光：亮蓝色或青色</li><li>点睛色：白色、能量黄或亮青色</li></ul><p>色彩原则：</p><ul><li>现代、简洁、科技感强</li><li>不要颜色过多</li><li>可以有能量感，但不要做成游戏风或赛博杂糅风</li></ul><h2 id="方向一-智慧立方" tabindex="-1">方向一：智慧立方 <a class="header-anchor" href="#方向一-智慧立方" aria-label="Permalink to &quot;方向一：智慧立方&quot;">​</a></h2><h3 id="方向定义" tabindex="-1">方向定义 <a class="header-anchor" href="#方向定义" aria-label="Permalink to &quot;方向定义&quot;">​</a></h3><p>强调“架构感、系统性、控制力”。</p><h3 id="核心画面" tabindex="-1">核心画面 <a class="header-anchor" href="#核心画面" aria-label="Permalink to &quot;核心画面&quot;">​</a></h3><p>一个半透明的立方体，象征稳固的数字系统与平台架构。</p><p>立方体内部有多条发光的数据流穿梭、交汇，最终在某个顶点汇聚，并触发一道简洁的闪电符号。</p><h3 id="传达重点" tabindex="-1">传达重点 <a class="header-anchor" href="#传达重点" aria-label="Permalink to &quot;传达重点&quot;">​</a></h3><ul><li>平台架构稳定</li><li>调度发生在系统内部</li><li>多租户、隔离、治理、控制感明确</li><li>智能决策最终落到一个可执行的触发点</li></ul><h3 id="设计语言" tabindex="-1">设计语言 <a class="header-anchor" href="#设计语言" aria-label="Permalink to &quot;设计语言&quot;">​</a></h3><ul><li>硬朗几何</li><li>结构清晰</li><li>动态数据流作为内部张力</li></ul><h3 id="推荐色彩" tabindex="-1">推荐色彩 <a class="header-anchor" href="#推荐色彩" aria-label="Permalink to &quot;推荐色彩&quot;">​</a></h3><ul><li>立方体框架：深空灰、哑光银</li><li>数据流：科技蓝到青色渐变</li><li>闪电：亮白或能量黄</li></ul><h2 id="方向二-神经涌流" tabindex="-1">方向二：神经涌流 <a class="header-anchor" href="#方向二-神经涌流" aria-label="Permalink to &quot;方向二：神经涌流&quot;">​</a></h2><h3 id="方向定义-1" tabindex="-1">方向定义 <a class="header-anchor" href="#方向定义-1" aria-label="Permalink to &quot;方向定义&quot;">​</a></h3><p>强调“智能中枢、连接网络、调度扩散”。</p><h3 id="核心画面-1" tabindex="-1">核心画面 <a class="header-anchor" href="#核心画面-1" aria-label="Permalink to &quot;核心画面&quot;">​</a></h3><p>由神经元节点和连接线组成一个抽象网络，整体轮廓接近字母 <code>Z</code>。</p><p>网络中心有一个脉动光点，象征调度中枢；当一次决策发生时，光沿既定路径迅速传递，形成一次清晰的“调度波”。</p><h3 id="传达重点-1" tabindex="-1">传达重点 <a class="header-anchor" href="#传达重点-1" aria-label="Permalink to &quot;传达重点&quot;">​</a></h3><ul><li>平台具有智能理解与协同能力</li><li>调度不是随机触发，而是有路径和逻辑的</li><li>各种能力模块通过网络化方式联通</li></ul><h3 id="设计语言-1" tabindex="-1">设计语言 <a class="header-anchor" href="#设计语言-1" aria-label="Permalink to &quot;设计语言&quot;">​</a></h3><ul><li>有机</li><li>发光</li><li>节点连接感强</li><li>智能生命感更明显</li></ul><h3 id="推荐色彩-1" tabindex="-1">推荐色彩 <a class="header-anchor" href="#推荐色彩-1" aria-label="Permalink to &quot;推荐色彩&quot;">​</a></h3><ul><li>网络底色：幽蓝色</li><li>中枢光点：青色或紫色</li><li>调度波：亮白色光晕</li></ul><h2 id="方向三-无限门径" tabindex="-1">方向三：无限门径 <a class="header-anchor" href="#方向三-无限门径" aria-label="Permalink to &quot;方向三：无限门径&quot;">​</a></h2><h3 id="方向定义-2" tabindex="-1">方向定义 <a class="header-anchor" href="#方向定义-2" aria-label="Permalink to &quot;方向定义&quot;">​</a></h3><p>强调“工作流、通道、可控流转和无限扩展”。</p><h3 id="核心画面-2" tabindex="-1">核心画面 <a class="header-anchor" href="#核心画面-2" aria-label="Permalink to &quot;核心画面&quot;">​</a></h3><p>以莫比乌斯环或 <code>∞</code> 变体为基础，将其带面设计成数据通路。</p><p>在关键转折点，通路收束抬升，形成一个“门”或“桥”的视觉隐喻，一束光从中穿过，代表自动化工作流被安全、精确地调度执行。</p><h3 id="传达重点-2" tabindex="-1">传达重点 <a class="header-anchor" href="#传达重点-2" aria-label="Permalink to &quot;传达重点&quot;">​</a></h3><ul><li>自动化流不是离散动作，而是连续系统</li><li>经验可以沉淀、复用、迁移</li><li>平台是流转通道和裁决关口</li></ul><h3 id="设计语言-2" tabindex="-1">设计语言 <a class="header-anchor" href="#设计语言-2" aria-label="Permalink to &quot;设计语言&quot;">​</a></h3><ul><li>优雅</li><li>循环</li><li>流线型</li><li>有路径哲学感</li></ul><h3 id="推荐色彩-2" tabindex="-1">推荐色彩 <a class="header-anchor" href="#推荐色彩-2" aria-label="Permalink to &quot;推荐色彩&quot;">​</a></h3><ul><li>主体：科技蓝或深紫色渐变</li><li>数据通路：亮色光带</li><li>门径光束：白色或亮绿色</li></ul><h2 id="三个方向的差异" tabindex="-1">三个方向的差异 <a class="header-anchor" href="#三个方向的差异" aria-label="Permalink to &quot;三个方向的差异&quot;">​</a></h2><table><thead><tr><th>方向</th><th>更偏重的能力</th><th>更适合的品牌气质</th></tr></thead><tbody><tr><td>智慧立方</td><td>架构、治理、控制、安全</td><td>稳定、平台化、企业级</td></tr><tr><td>神经涌流</td><td>智能、协同、连接、调度</td><td>前沿、灵动、智能感强</td></tr><tr><td>无限门径</td><td>流程、通道、经验复用、生态</td><td>优雅、连续、产品化</td></tr></tbody></table><h2 id="当前建议" tabindex="-1">当前建议 <a class="header-anchor" href="#当前建议" aria-label="Permalink to &quot;当前建议&quot;">​</a></h2><p>如果 Logo 第一阶段更希望服务平台对外表达，而不是只服务技术团队内部认知，建议优先考虑这条组合路线：</p><p><strong>以“无限门径”的整体结构为骨架，吸收“神经涌流”的智能连接感，再加入“智慧立方”的局部几何控制感。</strong></p><p>这条路线更适合“智流”当前的产品语义：</p><ul><li>既不是纯工具</li><li>也不是纯聊天产品</li><li>而是一套在可控边界内调度真实能力流转的执行平台</li></ul><h2 id="后续可以继续补充的内容" tabindex="-1">后续可以继续补充的内容 <a class="header-anchor" href="#后续可以继续补充的内容" aria-label="Permalink to &quot;后续可以继续补充的内容&quot;">​</a></h2><p>后续这个目录可以继续加入：</p><ul><li>黑白稿方向</li><li>单色版与反白版规范</li><li>图标版与中英文组合版</li><li>Favicon / App Icon 缩略测试</li><li>GitHub、Web、后台、CLI 场景适配稿</li></ul><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>“智流”的 Logo 不应该停留在“AI + 闪电”的表层符号，而应该体现：</p><ul><li>有中枢判断</li><li>有流动路径</li><li>有系统边界</li><li>有精确触发</li></ul><p>它最终应当成为一个同时代表 <strong>智能、流转、控制、执行</strong> 的平台级识别符号。</p>',85)]))}const b=l(o,[["render",r]]);export{p as __pageData,b as default};
